def validate(args, output):
    n = args[0]
    if not isinstance(output, list):
        return False
    size = 1 << n
    if len(output) != size:
        return False
    for v in output:
        if not isinstance(v, int) or v < 0 or v >= size:
            return False
    if output[0] != 0:
        return False
    if len(set(output)) != size:
        return False
    for i in range(size):
        a = output[i]
        b = output[(i + 1) % size]
        diff = a ^ b
        if diff == 0 or (diff & (diff - 1)) != 0:
            return False
    return True

