function validate(args, output) {
    const n = args[0];
    if (!Array.isArray(output)) return false;
    const size = 1 << n;
    if (output.length !== size) return false;
    const seen = new Set();
    for (const v of output) {
        if (!Number.isInteger(v) || v < 0 || v >= size) return false;
        seen.add(v);
    }
    if (output[0] !== 0) return false;
    if (seen.size !== size) return false;
    for (let i = 0; i < size; i++) {
        const a = output[i];
        const b = output[(i + 1) % size];
        const diff = a ^ b;
        if (diff === 0 || (diff & (diff - 1)) !== 0) return false;
    }
    return true;
}

